/*
P2717 寒假作业
前缀和+离散化+树状数组
算法复杂度 O(n log n)
1.统计 a[i]-k 的前缀和
2.离散化前缀和
3.遍历 i，选出所有 s[j]<=s[i] (0<=j<i) 的 j
*/
#include <bits/stdc++.h>
using namespace std;

const int N=1e5+5;

int n,k,a[N],s[N],ls[N],c[N];
long long ans=0;
map<int,int> id;

int lowbit(int x){
    return x&(-x);
}

void add(int x){
    for(;x<=n+1;x+=lowbit(x))
        c[x]++;
}

int ask(int x){
    int sum=0;
    for(;x;x-=lowbit(x))
        sum+=c[x];
    return sum;
}

int main(){
    scanf("%d%d",&n,&k);
    for(int i=1;i<=n;i++){
        scanf("%d",&a[i]);
        s[i]=s[i-1]+(a[i]-k);
        ls[i]=s[i-1];
    }
    ls[n+1]=s[n];
    sort(ls+1,ls+n+2);
    int len=unique(ls+1,ls+n+2)-ls-1;
    for(int i=1;i<=len;i++)
        id[ls[i]]=i;
    for(int i=1;i<=n;i++){
        add(id[s[i-1]]);
        ans+=ask(id[s[i]]);
    }
    printf("%lld",ans);
    return 0;
}
